def assess(record: dict) -> str:
    required = {'created', 'resource', 'method', 'status', 'case_id'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + missing[0]
    meets = not (record["status"] == 200 and record["method"] == "GET")
    return "PASS" if meets else 'RETURN_CORRECT_HTTP_STATUS'

